<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Fees';
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); if(post('form')==='invoice'){executeSql('INSERT INTO fees_invoices(student_id,invoice_no,amount,due_date,status) VALUES (?,?,?,?,?)',[(int)post('student_id'), 'INV'.time().rand(10,99), (float)post('amount','0'), post('due_date'), 'Pending']);} else {executeSql('INSERT INTO payments(invoice_id,amount,method,reference_no,paid_at) VALUES (?,?,?,?,NOW())',[(int)post('invoice_id'),(float)post('amount','0'),post('method'),post('reference_no')]); executeSql('UPDATE fees_invoices i SET status = IF((SELECT COALESCE(SUM(p.amount),0) FROM payments p WHERE p.invoice_id=i.id) >= i.amount, "Paid", "Partial") WHERE i.id=?',[(int)post('invoice_id')]);} header('Location: index.php'); exit; }
$students=fetchAll('SELECT id,full_name FROM students ORDER BY full_name'); $invoices=fetchAll('SELECT i.*,s.full_name,(SELECT COALESCE(SUM(amount),0) FROM payments p WHERE p.invoice_id=i.id) paid FROM fees_invoices i JOIN students s ON s.id=i.student_id ORDER BY i.id DESC');
include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><h5>Create Invoice</h5><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="form" value="invoice"><div class="col"><select name="student_id" class="form-select"><?php foreach($students as $s):?><option value="<?=$s['id']?>"><?=e($s['full_name'])?></option><?php endforeach;?></select></div><div class="col"><input type="number" step="0.01" name="amount" class="form-control" placeholder="Amount"></div><div class="col"><input type="date" name="due_date" class="form-control"></div><div class="col"><button class="btn btn-primary">Create</button></div></form><hr><h5>Add Payment</h5><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="form" value="payment"><div class="col"><select name="invoice_id" class="form-select"><?php foreach($invoices as $i):?><option value="<?=$i['id']?>"><?=e($i['invoice_no'].' - '.$i['full_name'])?></option><?php endforeach;?></select></div><div class="col"><input type="number" step="0.01" name="amount" class="form-control" placeholder="Paid Amount"></div><div class="col"><select name="method" class="form-select"><option>Cash</option><option>Card</option><option>UPI</option><option>Online</option></select></div><div class="col"><input name="reference_no" class="form-control" placeholder="Ref"></div><div class="col"><button class="btn btn-success">Pay</button></div></form><hr><table class="table"><tr><th>Invoice</th><th>Student</th><th>Amount</th><th>Paid</th><th>Status</th></tr><?php foreach($invoices as $i):?><tr><td><?=e($i['invoice_no'])?></td><td><?=e($i['full_name'])?></td><td><?=$i['amount']?></td><td><?=$i['paid']?></td><td><?=$i['status']?></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
